advanced.PriceWithCurrency:
// JavaScript
import "@maersk-global/mds-components-core/mc-input-group";
import "@maersk-global/mds-components-core/mc-input";
import "@maersk-global/mds-components-core/mc-select";

// Numeric validation
setTimeout(() => {
  const input = document.querySelector('mc-input') as HTMLElement & { __numericValidationAttached?: boolean };
  if (input && !input.__numericValidationAttached) {
    const DIGITS_PATTERN = '^-?[0-9]*\\.?[0-9]*$';
    input.addEventListener('beforeinput', (event: InputEvent) => {
      if (event.data && !new RegExp(DIGITS_PATTERN, 'g').test(event.data)) {
        event.preventDefault();
      }
    });
    input.__numericValidationAttached = true;
  }
}, 0);

// CSS
mc-select {
  width: 94px;
}
mc-input {
  width: 100px;
}
// HTML
<mc-input-group legend="Price">
  <mc-input hiddenlabel></mc-input>
  <mc-select value="1" hiddenlabel>
    <mc-option value="1">USD</mc-option>
    <mc-option value="2">EUR</mc-option>
    <mc-option value="3">GBP</mc-option>
    <mc-option value="4">JPY</mc-option>
    <mc-option value="5">CNY</mc-option>
  </mc-select>
</mc-input-group>

advanced.RouteSelector:
// JavaScript
import "@maersk-global/mds-components-core/mc-input-group";
import "@maersk-global/mds-components-core/mc-typeahead";
import "@maersk-global/mds-components-core/mc-button";

const swapInputs = () => {
  const inputGroup = document.querySelector('mc-input-group');
  if (inputGroup) {
    const typeaheads = inputGroup.querySelectorAll('mc-typeahead');
    if (typeaheads.length === 2) {
      const [firstTypeahead, secondTypeahead] = typeaheads;

      // Swap placeholders
      const firstPlaceholder = firstTypeahead.getAttribute('placeholder');
      const secondPlaceholder = secondTypeahead.getAttribute('placeholder');
      firstTypeahead.setAttribute('placeholder', secondPlaceholder || '');
      secondTypeahead.setAttribute('placeholder', firstPlaceholder || '');

      // Swap values
      const firstValue = firstTypeahead.value;
      const secondValue = secondTypeahead.value;
      firstTypeahead.value = secondValue;
      secondTypeahead.value = firstValue;

      // Swap options content
      const firstOptions = Array.from(firstTypeahead.querySelectorAll('mc-option'));
      const secondOptions = Array.from(secondTypeahead.querySelectorAll('mc-option'));

      // Clear existing options
      firstOptions.forEach(option => option.remove());
      secondOptions.forEach(option => option.remove());

      // Add options to swapped typeaheads
      secondOptions.forEach(option => firstTypeahead.appendChild(option));
      firstOptions.forEach(option => secondTypeahead.appendChild(option));
    }
  }
};

// HTML
<div style="min-width: 300px;">
<mc-input-group hiddenlegend>
  <mc-typeahead label="From" value="Copenhagen" clearbutton>
    <mc-option value="1">Copenhagen</mc-option>
    <mc-option value="2">Amsterdam</mc-option>
    <mc-option value="3">Berlin</mc-option>
    <mc-option value="4">London</mc-option>
    <mc-option value="5">New York</mc-option>
  </mc-typeahead>
  <mc-button
    variant="outlined"
    appearance="neutral"
    hiddenlabel
    icon="arrows-left-right"
    @click=swapInputs()
  ></mc-button>
  <mc-typeahead label="To" value="Shanghai" clearbutton>
    <mc-option value="1">Shanghai</mc-option>
    <mc-option value="2">Toronto</mc-option>
    <mc-option value="3">Tokyo</mc-option>
    <mc-option value="4">Dubai</mc-option>
    <mc-option value="5">Singapore</mc-option>
  </mc-typeahead>
</mc-input-group>
</div>
